 17→package org.apache.kafka.streams.processor.internals.tasks;
 18→
 19→import org.apache.kafka.common.KafkaFuture;
 20→import org.apache.kafka.common.errors.TimeoutException;
 21→import org.apache.kafka.common.internals.KafkaFutureImpl;
 22→import org.apache.kafka.common.utils.LogContext;
 23→import org.apache.kafka.common.utils.Time;
 24→import org.apache.kafka.streams.errors.StreamsException;
 25→import org.apache.kafka.streams.errors.TaskMigratedException;
 26→import org.apache.kafka.streams.processor.internals.ProcessingThread;
 27→import org.apache.kafka.streams.processor.internals.ReadOnlyTask;
 28→import org.apache.kafka.streams.processor.internals.StreamTask;
 29→import org.apache.kafka.streams.processor.internals.Task;
 30→import org.apache.kafka.streams.processor.internals.TaskExecutionMetadata;
 31→
 32→import org.slf4j.Logger;
 33→
 34→import java.time.Duration;
 35→import java.util.concurrent.atomic.AtomicBoolean;
 36→import java.util.concurrent.atomic.AtomicReference;
 37→
 38→import static org.apache.kafka.streams.internals.StreamsConfigUtils.ProcessingMode.EXACTLY_ONCE_V2;
 39→
 40→public class DefaultTaskExecutor implements TaskExecutor {
 41→
 42→    private class TaskExecutorThread extends Thread implements ProcessingThread {
 43→
 44→        private final AtomicBoolean shutdownRequested = new AtomicBoolean(false);
 45→        private final AtomicReference<KafkaFutureImpl<StreamTask>> taskReleaseRequested = new AtomicReference<>(null);
 46→
 47→        private final Logger log;
 48→
 49→        public TaskExecutorThread(final String name) {
 50→            super(name);
 51→            final String logPrefix = String.format("%s ", name);
 52→            final LogContext logContext = new LogContext(logPrefix);
 53→            log = logContext.logger(DefaultTaskExecutor.class);
 54→        }
 55→
 56→        @Override
 57→        public void run() {
 58→            log.info("Task executor thread started");
 59→            try {
 60→                while (!shutdownRequested.get()) {
 61→                    try {
 62→                        runOnce(time.milliseconds());
 63→                    } catch (final StreamsException e) {
 64→                        handleException(e);
 65→                    } catch (final Exception e) {
 66→                        handleException(new StreamsException(e));
 67→                    }
 68→                }
 69→            } finally {
 70→                if (currentTask != null) {
 71→                    log.debug("Releasing task {} due to shutdown.", currentTask.id());
 72→                    unassignCurrentTask();
 73→                }
 74→
 75→                final KafkaFutureImpl<StreamTask> taskReleaseFuture;
 76→                if ((taskReleaseFuture = taskReleaseRequested.getAndSet(null)) != null) {
 77→                    log.debug("Asked to return current task, but shutting down.");
 78→                    taskReleaseFuture.complete(null);
 79→                }
 80→                log.info("Task executor thread shutdown");
 81→            }
 82→        }
 83→
 84→        private void handleTaskReleaseRequested() {
 85→            final KafkaFutureImpl<StreamTask> taskReleaseFuture;
 86→            if ((taskReleaseFuture = taskReleaseRequested.getAndSet(null)) != null) {
 87→                if (currentTask != null) {
 88→                    log.debug("Releasing task {} upon request.", currentTask.id());
 89→                    final StreamTask unassignedTask = unassignCurrentTask();
 90→                    taskReleaseFuture.complete(unassignedTask);
 91→                } else {
 92→                    log.debug("Asked to return current task, but returned current task already.");
 93→                    taskReleaseFuture.complete(null);
 94→                }
 95→            }
 96→        }
 97→
 98→        private void handleException(final StreamsException e) {
 99→            if (currentTask != null) {
100→                taskManager.setUncaughtException(e, currentTask.id());
101→
102→                log.debug("Releasing task {} due to uncaught exception.", currentTask.id());
103→                unassignCurrentTask();
104→            } else {
105→                // If we do not currently have a task assigned and still get an error, this is fatal for the executor thread
106→                throw e;
107→            }
108→        }
109→
110→        private void runOnce(final long nowMs) {
111→            handleTaskReleaseRequested();
112→
113→            if (currentTask == null) {
114→                currentTask = taskManager.assignNextTask(DefaultTaskExecutor.this);
115→            }
116→
117→            if (currentTask == null) {
118→                try {
119→                    taskManager.awaitProcessableTasks(shutdownRequested::get);
120→                } catch (final InterruptedException ignored) {
121→                    // Can be ignored, the cause of the interrupted will be handled in the event loop
122→                }
123→            } else {
124→                boolean progressed = false;
125→
126→                if (taskExecutionMetadata.canProcessTask(currentTask, nowMs) && currentTask.isProcessable(nowMs)) {
127→                    if (processTask(currentTask, nowMs, time)) {
128→                        log.trace("processed a record for {}", currentTask.id());
129→                        progressed = true;
130→                    }
131→                }
132→
133→                if (taskExecutionMetadata.canPunctuateTask(currentTask)) {
134→                    if (currentTask.maybePunctuateStreamTime()) {
135→                        log.trace("punctuated stream time for task {} ", currentTask.id());
136→                        progressed = true;
137→                    }
138→                    if (currentTask.maybePunctuateSystemTime()) {
139→                        log.trace("punctuated system time for task {} ", currentTask.id());
140→                        progressed = true;
141→                    }
142→                }
143→
144→                if (!progressed) {
145→                    log.debug("Releasing task {} because we are not making progress.", currentTask.id());
146→                    unassignCurrentTask();
147→                }
148→            }
149→        }
150→
151→        private boolean processTask(final Task task, final long now, final Time time) {
152→            boolean processed = false;
153→            try {
154→                processed = task.process(now);
155→                if (processed) {
156→                    log.trace("Successfully processed task {}", task.id());
157→                    task.clearTaskTimeout();
158→                    // TODO: enable regardless of whether using named topologies
159→                    if (taskExecutionMetadata.hasNamedTopologies() && taskExecutionMetadata.processingMode() != EXACTLY_ONCE_V2) {
160→                        taskExecutionMetadata.addToSuccessfullyProcessed(task);
161→                    }
162→                }
163→            } catch (final TimeoutException timeoutException) {
164→                // TODO consolidate TimeoutException retries with general error handling
165→                task.maybeInitTaskTimeoutOrThrow(now, timeoutException);
166→                log.error(
167→                    String.format(
168→                        "Could not complete processing records for %s due to the following exception; will move to next task and retry later",
169→                        task.id()),
170→                    timeoutException
171→                );
172→            } catch (final TaskMigratedException e) {
173→                log.info("Failed to process stream task {} since it got migrated to another thread already. " +
174→                    "Will trigger a new rebalance and close all tasks as zombies together.", task.id());
175→                throw e;
176→            } catch (final StreamsException e) {
177→                log.error(String.format("Failed to process stream task %s due to the following error:", task.id()), e);
178→                e.setTaskId(task.id());
179→                throw e;
180→            } catch (final RuntimeException e) {
181→                log.error(String.format("Failed to process stream task %s due to the following error:", task.id()), e);
182→                throw new StreamsException(e, task.id());
183→            } finally {
184→                task.recordProcessBatchTime(time.milliseconds() - now);
185→            }
186→            return processed;
187→        }
188→
189→        private StreamTask unassignCurrentTask() {
190→            if (currentTask == null)
191→                throw new IllegalStateException("Does not own any task while being ask to unassign from task manager");
192→
193→            // flush the task before giving it back to task manager, if we are not handing it back because of an error.
194→            if (!taskManager.hasUncaughtException(currentTask.id())) {
195→                try {
196→                    currentTask.flush();
197→                } catch (final StreamsException e) {
198→                    log.error(String.format("Failed to flush stream task %s due to the following error:", currentTask.id()), e);
199→                    e.setTaskId(currentTask.id());
200→                    taskManager.setUncaughtException(e, currentTask.id());
201→                } catch (final RuntimeException e) {
202→                    log.error(String.format("Failed to flush stream task %s due to the following error:", currentTask.id()), e);
203→                    taskManager.setUncaughtException(new StreamsException(e, currentTask.id()), currentTask.id());
204→                }
205→            }
206→            taskManager.unassignTask(currentTask, DefaultTaskExecutor.this);
207→
208→            final StreamTask retTask = currentTask;
209→            currentTask = null;
210→            return retTask;
211→        }
212→    }
213→
214→    private final Time time;
215→    private final String name;
216→    private final TaskManager taskManager;
217→    private final TaskExecutionMetadata taskExecutionMetadata;
218→    private final Logger log;
219→
220→    private StreamTask currentTask = null;
221→    private TaskExecutorThread taskExecutorThread = null;
222→
223→    public DefaultTaskExecutor(final TaskManager taskManager,
224→                               final String name,
225→                               final Time time,
226→                               final TaskExecutionMetadata taskExecutionMetadata) {
227→        this.time = time;
228→        this.name = name;
229→        this.taskManager = taskManager;
230→        this.taskExecutionMetadata = taskExecutionMetadata;
231→        final LogContext logContext = new LogContext(name);
232→        this.log = logContext.logger(DefaultTaskExecutor.class);
233→    }
234→
235→    @Override
236→    public String name() {
237→        return name;
238→    }
239→
240→    @Override
241→    public void start() {
242→        if (taskExecutorThread == null) {
243→            taskExecutorThread = new TaskExecutorThread(name);
244→            taskExecutorThread.start();
245→        }
246→    }
247→
248→    @Override
249→    public boolean isRunning() {
250→        return taskExecutorThread != null && taskExecutorThread.isAlive();
251→    }
252→
253→    @Override
254→    public void requestShutdown() {
255→        if (taskExecutorThread != null) {
256→            taskExecutorThread.shutdownRequested.set(true);
257→        }
258→    }
259→
260→    @Override
261→    public void awaitShutdown(final Duration timeout) {
262→        if (taskExecutorThread != null) {
263→            try {
264→                taskExecutorThread.join(timeout.toMillis());
265→                if (taskExecutorThread.isAlive()) {
266→                    throw new StreamsException("State updater thread did not shutdown within the timeout");
267→                }
268→                taskExecutorThread = null;
269→            } catch (final InterruptedException ignored) {
270→            }
271→        }
272→    }
273→
274→    @Override
275→    public ReadOnlyTask currentTask() {
276→        return currentTask != null ? new ReadOnlyTask(currentTask) : null;
277→    }
278→
279→    @Override
280→    public KafkaFuture<StreamTask> unassign() {
281→        final KafkaFutureImpl<StreamTask> future = new KafkaFutureImpl<>();
282→
283→        if (taskExecutorThread != null) {
284→            log.debug("Asking {} to hand back task", taskExecutorThread.getName());
285→            if (!taskExecutorThread.taskReleaseRequested.compareAndSet(null, future)) {
286→                throw new IllegalStateException("There was already a task release request registered");
287→            }
288→            if (!taskExecutorThread.isAlive()) {
289→                log.debug("Completing future, because task executor was just shut down");
290→                future.complete(null);
291→            } else {
292→                taskManager.signalTaskExecutors();
293→            }
294→        } else {
295→            log.debug("Tried to unassign but no thread is running");
296→            future.complete(null);
297→        }
298→
299→        return future;
300→    }
301→}
