214→    boolean handleCorruption(final Set<TaskId> corruptedTasks) {
215→        final Set<TaskId> activeTasks = new HashSet<>(tasks.activeInitializedTaskIds());
216→
217→        // We need to stop all processing, since we need to commit non-corrupted tasks as well.
218→        maybeLockTasks(activeTasks);
219→
220→        final Set<Task> corruptedActiveTasks = new TreeSet<>(Comparator.comparing(Task::id));
221→        final Set<Task> corruptedStandbyTasks = new TreeSet<>(Comparator.comparing(Task::id));
222→
223→        for (final TaskId taskId : corruptedTasks) {
224→            final Task task = tasks.initializedTask(taskId);
225→            if (task.isActive()) {
226→                corruptedActiveTasks.add(task);
227→            } else {
228→                corruptedStandbyTasks.add(task);
229→            }
230→        }
231→
232→        // Make sure to clean up any corrupted standby tasks in their entirety before committing
233→        // since TaskMigrated can be thrown and the resulting handleLostAll will only clean up active tasks
234→        closeDirtyAndRevive(corruptedStandbyTasks, true);
235→
236→        // We need to commit before closing the corrupted active tasks since this will force the ongoing txn to abort
237→        try {
238→            final Collection<Task> tasksToCommit = tasks.allInitializedTasksPerId()
239→                .values()
240→                .stream()
241→                .filter(t -> t.state() == Task.State.RUNNING)
242→                .filter(t -> !corruptedTasks.contains(t.id()))
243→                .collect(Collectors.toSet());
244→            commitTasksAndMaybeUpdateCommittableOffsets(tasksToCommit, new HashMap<>());
245→        } catch (final TaskCorruptedException e) {
246→            log.info("Some additional tasks were found corrupted while trying to commit, these will be added to the " +
247→                         "tasks to clean and revive: {}", e.corruptedTasks());
248→            corruptedActiveTasks.addAll(tasks.initializedTasks(e.corruptedTasks()));
249→        } catch (final TimeoutException e) {
250→            log.info("Hit TimeoutException when committing all non-corrupted tasks, these will be closed and revived");
251→            final Collection<Task> uncorruptedTasks = new HashSet<>(tasks.activeInitializedTasks());
252→            uncorruptedTasks.removeAll(corruptedActiveTasks);
253→            // Those tasks which just timed out can just be closed dirty without marking changelogs as corrupted
254→            closeDirtyAndRevive(uncorruptedTasks, false);
255→        }
256→
257→        closeDirtyAndRevive(corruptedActiveTasks, true);
258→
259→        maybeUnlockTasks(activeTasks);
260→
261→        return !corruptedActiveTasks.isEmpty();
262→    }
