264→    private void closeDirtyAndRevive(final Collection<Task> taskWithChangelogs, final boolean markAsCorrupted) {
265→        for (final Task task : taskWithChangelogs) {
266→            if (task.state() != State.CLOSED) {
267→                try {
268→                    // we do not need to take the returned offsets since we are not going to commit anyways;
269→                    // this call is only used for active tasks to flush the cache before suspending and
270→                    // closing the topology
271→                    task.prepareCommit(false);
272→                } catch (final RuntimeException swallow) {
273→                    log.warn("Error flushing cache for corrupted task {}. " +
274→                        "Since the task is closing dirty, the following exception is swallowed: {}",
275→                        task.id(), swallow.getMessage());
276→                }
277→
278→                try {
279→                    task.suspend();
280→
281→                    // we need to enforce a checkpoint that removes the corrupted partitions
282→                    if (markAsCorrupted) {
283→                        task.postCommit(true);
284→                    }
285→                } catch (final RuntimeException swallow) {
286→                    log.warn("Error suspending corrupted task {}. " +
287→                        "Since the task is closing dirty, the following exception is swallowed: {}",
288→                        task.id(), swallow.getMessage());
289→                }
290→                task.closeDirty();
291→            }
292→            // For active tasks pause their input partitions so we won't poll any more records
293→            // for this task until it has been re-initialized;
294→            // Note, closeDirty already clears the partition-group for the task.
295→            if (task.isActive()) {
296→                final Set<TopicPartition> currentAssignment = mainConsumer.assignment();
297→                final Set<TopicPartition> taskInputPartitions = task.inputPartitions();
298→                final Set<TopicPartition> assignedToPauseAndReset =
299→                    intersection(HashSet::new, currentAssignment, taskInputPartitions);
300→                if (!assignedToPauseAndReset.equals(taskInputPartitions)) {
301→                    log.warn(
302→                        "Expected the current consumer assignment {} to contain the input partitions {}. " +
303→                            "Will proceed to recover.",
304→                        currentAssignment,
305→                        taskInputPartitions
306→                    );
307→                }
308→
309→                task.addPartitionsForOffsetReset(assignedToPauseAndReset);
310→            }
311→
312→            tasks.removeTask(task);
313→            task.revive();
314→            tasks.addPendingTasksToInit(Collections.singleton(task));
315→        }
316→    }
