410→    // Wrap and throw the exception in the following order
411→    // if at least one of the exception is a non-streams exception, then wrap and throw since it should be handled by thread's handler
412→    // if at least one of the exception is a streams exception, then directly throw since it should be handled by thread's handler
413→    // if at least one of the exception is a task-migrated exception, then directly throw since it indicates all tasks are lost
414→    // otherwise, all the exceptions are task-corrupted, then merge their tasks and throw a single one
415→    // TODO: move task-corrupted and task-migrated out of the public errors package since they are internal errors and always be
416→    //       handled by Streams library itself
417→    private void maybeThrowTaskExceptions(final Map<TaskId, RuntimeException> taskExceptions) {
418→        if (!taskExceptions.isEmpty()) {
419→            log.error("Get exceptions for the following tasks: {}", taskExceptions);
420→
421→            final Set<TaskId> aggregatedCorruptedTaskIds = new HashSet<>();
422→            StreamsException lastFatal = null;
423→            TaskMigratedException lastTaskMigrated = null;
424→            for (final Map.Entry<TaskId, RuntimeException> entry : taskExceptions.entrySet()) {
425→                final TaskId taskId = entry.getKey();
426→                final RuntimeException exception = entry.getValue();
427→
428→                if (exception instanceof StreamsException) {
429→                    if (exception instanceof TaskMigratedException) {
430→                        lastTaskMigrated = (TaskMigratedException) exception;
431→                    } else if (exception instanceof TaskCorruptedException) {
432→                        log.warn("Encounter corrupted task " + taskId + ", will group it with other corrupted tasks " +
433→                            "and handle together", exception);
434→                        aggregatedCorruptedTaskIds.add(taskId);
435→                    } else {
436→                        ((StreamsException) exception).setTaskId(taskId);
437→                        lastFatal = (StreamsException) exception;
438→                    }
439→                } else if (exception instanceof KafkaException) {
440→                    lastFatal = new StreamsException(exception, taskId);
441→                } else {
442→                    lastFatal = new StreamsException("Encounter unexpected fatal error for task " + taskId, exception, taskId);
443→                }
444→            }
445→
446→            if (lastFatal != null) {
447→                throw lastFatal;
448→            } else if (lastTaskMigrated != null) {
449→                throw lastTaskMigrated;
450→            } else {
451→                throw new TaskCorruptedException(aggregatedCorruptedTaskIds);
452→            }
453→        }
454→    }
