1067→        // any exception and rethrow it at the end. some exceptions may be handled immediately and then swallowed,
1068→        // as such we just need to skip those dirty tasks in the checkpoint
1069→        final Set<Task> dirtyTasks = new TreeSet<>(Comparator.comparing(Task::id));
1070→        try {
1071→            if (revokedTasksNeedCommit) {
1072→                // in handleRevocation we must call commitOffsetsOrTransaction() directly rather than
1073→                // commitAndFillInConsumedOffsetsAndMetadataPerTaskMap() to make sure we don't skip the
1074→                // offset commit because we are in a rebalance
1075→                taskExecutor.commitOffsetsOrTransaction(consumedOffsetsPerTask);
1076→            }
1077→        } catch (final TaskCorruptedException e) {
1078→            log.warn("Some tasks were corrupted when trying to commit offsets, these will be cleaned and revived: {}",
1079→                     e.corruptedTasks());
1080→
1081→            // If we hit a TaskCorruptedException it must be EOS, just handle the cleanup for those corrupted tasks right here
1082→            dirtyTasks.addAll(tasks.initializedTasks(e.corruptedTasks()));
1083→            closeDirtyAndRevive(dirtyTasks, true);
1084→        } catch (final TimeoutException e) {
1085→            log.warn("Timed out while trying to commit all tasks during revocation, these will be cleaned and revived");
1086→
1087→            // If we hit a TimeoutException it must be ALOS, just close dirty and revive without wiping the state
1088→            dirtyTasks.addAll(consumedOffsetsPerTask.keySet());
1089→            closeDirtyAndRevive(dirtyTasks, false);
1090→        } catch (final RuntimeException e) {
1091→            log.error("Exception caught while committing those revoked tasks " + revokedActiveTasks, e);
1092→            firstException.compareAndSet(null, e);
1093→            dirtyTasks.addAll(consumedOffsetsPerTask.keySet());
1094→        }
1095→
1096→        // we enforce checkpointing upon suspending a task: if it is resumed later we just proceed normally, if it is
1097→        // going to be closed we would checkpoint by then
1098→        for (final Task task : revokedActiveTasks) {
1099→            if (!dirtyTasks.contains(task)) {
1100→                try {
1101→                    task.postCommit(true);
1102→                } catch (final RuntimeException e) {
1103→                    log.error("Exception caught while post-committing task " + task.id(), e);
1104→                    maybeSetFirstException(false, maybeWrapTaskException(e, task.id()), firstException);
1105→                }
1106→            }
1107→        }
1108→
1109→        if (revokedTasksNeedCommit) {
1110→            for (final Task task : commitNeededActiveTasks) {
1111→                if (!dirtyTasks.contains(task)) {
1112→                    try {
1113→                        // for non-revoking active tasks, we should not enforce checkpoint
1114→                        // since if it is EOS enabled, no checkpoint should be written while
1115→                        // the task is in RUNNING tate
1116→                        task.postCommit(false);
1117→                    } catch (final RuntimeException e) {
1118→                        log.error("Exception caught while post-committing task " + task.id(), e);
1119→                        maybeSetFirstException(false, maybeWrapTaskException(e, task.id()), firstException);
1120→                    }
1121→                }
1122→            }
1123→        }
1124→
1125→        for (final Task task : revokedActiveTasks) {
1126→            try {
1127→                task.suspend();
1128→            } catch (final RuntimeException e) {
1129→                log.error("Caught the following exception while trying to suspend revoked task " + task.id(), e);
1130→                maybeSetFirstException(false, maybeWrapTaskException(e, task.id()), firstException);
1131→            }
1132→        }
1133→
1134→        maybeUnlockTasks(lockedTaskIds);
1135→
1136→        if (firstException.get() != null) {
1137→            throw firstException.get();
1138→        }
1139→    }
