1141→    private void revokeTasksInStateUpdater(final Set<TopicPartition> remainingRevokedPartitions) {
1142→        final Map<TaskId, CompletableFuture<StateUpdater.RemovedTaskResult>> futures = new LinkedHashMap<>();
1143→        final Map<TaskId, RuntimeException> failedTasksFromStateUpdater = new HashMap<>();
1144→        for (final Task restoringTask : stateUpdater.tasks()) {
1145→            if (restoringTask.isActive()) {
1146→                if (remainingRevokedPartitions.containsAll(restoringTask.inputPartitions())) {
1147→                    futures.put(restoringTask.id(), stateUpdater.remove(restoringTask.id(), StandbyUpdateListener.SuspendReason.MIGRATED));
1148→                    remainingRevokedPartitions.removeAll(restoringTask.inputPartitions());
1149→                }
1150→            }
1151→        }
1152→        getNonFailedTasks(futures, failedTasksFromStateUpdater).forEach(task -> {
1153→            task.suspend();
1154→            tasks.addActiveTask((StreamTask) task);
1155→        });
1156→
1157→        maybeThrowTaskExceptions(failedTasksFromStateUpdater);
1158→    }
