1236→    /**
1237→     * Compute the offset total summed across all stores in a task. Includes offset sum for any tasks we own the
1238→     * lock for, which includes assigned and unassigned tasks we locked in {@link #tryToLockAllNonEmptyTaskDirectories()}.
1239→     * Does not include stateless or non-logged tasks.
1240→     */
1241→    public Map<TaskId, Long> taskOffsetSums() {
1242→
1243→        // Not all tasks will create directories, and there may be directories for tasks we don't currently own,
1244→        // so we consider all tasks that are either owned or on disk. This includes stateless tasks, which should
1245→        // just have an empty changelogOffsets map.
1246→        final Map<TaskId, Task> tasks = allTasks();
1247→        final Set<TaskId> lockedTaskDirectoriesOfNonOwnedTasksAndClosedAndCreatedTasks =
1248→            union(HashSet::new, lockedTaskDirectories, tasks.keySet());
1249→
1250→        final Map<TaskId, Long> taskOffsetSums = stateDirectory.taskOffsetSums(lockedTaskDirectoriesOfNonOwnedTasksAndClosedAndCreatedTasks);
1251→
1252→        // overlay latest offsets from assigned tasks
1253→        for (final Task task : tasks.values()) {
1254→            // exclude stateless and non-logged tasks
1255→            if (task.isActive() && task.state() == State.RUNNING && !task.changelogPartitions().isEmpty()) {
1256→                taskOffsetSums.put(task.id(), Task.LATEST_OFFSET);
1257→            }
1258→        }
1259→
1260→        return taskOffsetSums;
1261→    }
