1263→    /**
1264→     * Makes a weak attempt to lock all non-empty task directories in the state dir. We are responsible for computing and
1265→     * reporting the offset sum for any unassigned tasks we obtain the lock for in the upcoming rebalance. Tasks
1266→     * that we locked but didn't own will be released at the end of the rebalance (unless of course we were
1267→     * assigned the task as a result of the rebalance). This method should be idempotent.
1268→     */
1269→    private void tryToLockAllNonEmptyTaskDirectories() {
1270→        // Always clear the set at the beginning as we're always dealing with the
1271→        // current set of actually-locked tasks.
1272→        lockedTaskDirectories.clear();
1273→
1274→        final Map<TaskId, Task> allTasks = allTasks();
1275→        for (final StateDirectory.TaskDirectory taskDir : stateDirectory.listNonEmptyTaskDirectories()) {
1276→            final File dir = taskDir.file();
1277→            final String namedTopology = taskDir.namedTopology();
1278→            try {
1279→                final TaskId id = parseTaskDirectoryName(dir.getName(), namedTopology);
1280→                if (stateDirectory.lock(id)) {
1281→                    // Check again in case the cleaner thread ran and emptied the directory
1282→                    if (stateDirectory.directoryForTaskIsEmpty(id)) {
1283→                        log.debug("Releasing lock on empty directory for task {}", id);
1284→                        stateDirectory.unlock(id);
1285→                    } else {
1286→                        lockedTaskDirectories.add(id);
1287→                        if (!allTasks.containsKey(id)) {
1288→                            log.debug("Temporarily locked unassigned task {} for the upcoming rebalance", id);
1289→                        }
1290→                    }
1291→                }
1292→            } catch (final TaskIdFormatException e) {
1293→                // ignore any unknown files that sit in the same directory
1294→            }
1295→        }
1296→    }
